use serde::Serialize;

#[derive(Debug, Clone, Serialize)]
pub struct Panel {
    pub id: String,
    pub name: String,
    pub dtbo: String,
}

// Filenames mirror the MB-folder layout in
// distribution/config/archr-dts/{original,clone,soysauce}/<MB>/ — one DTBO
// per motherboard revision, generated by config/mipi-generator/generator.sh
