pub fn get_panels(console: &str) -> Vec<Panel> {
    let source = match console {
        "original" => PANELS_ORIGINAL,
        "clone" => PANELS_CLONE,
        "soysauce" => PANELS_SOYSAUCE,
        _ => return vec![],
    };
    source.iter().map(|(id, name, dtbo)| Panel {
        id: id.to_string(),
        name: name.to_string(),
        dtbo: dtbo.to_string(),
    }).collect()
}
